INSERT INTO ai_knowledge_chunk (
    document_id, base_id, category_id, chunk_no, chunk_type, heading_path,
    content_text, keyword_text, content_length, sort_no, create_time
) VALUES

    (
        #{item.documentId}, #{item.baseId}, #{item.categoryId}, #{item.chunkNo}, #{item.chunkType}, #{item.headingPath},
        #{item.contentText}, #{item.keywordText}, #{item.contentLength}, #{item.sortNo}, #{item.createTime}
    )

mapper.select:
SELECT doc.id AS document_id, chunk.id AS chunk_id, doc.doc_title, doc.policy_region, chunk.heading_path, chunk.content_text AS snippet, chunk.keyword_text, chunk.chunk_no FROM ai_knowledge_chunk chunk INNER JOIN ai_knowledge_document doc ON doc.id = chunk.document_id WHERE doc.is_deleted = FALSE AND chunk.base_id = #{request.baseId}
AND chunk.category_id = #{request.categoryId}
AND ( chunk.content_text LIKE CONCAT('%', #{request.keywords}, '%') OR doc.doc_title LIKE CONCAT('%', #{request.keywords}, '%') OR COALESCE(chunk.keyword_text, '') LIKE CONCAT('%', #{request.keywords}, '%') )
AND doc.policy_region LIKE CONCAT('%', #{request.policyRegion}, '%')
AND (doc.effective_date IS NULL OR doc.effective_date <= CURRENT_DATE) AND (doc.expire_date IS NULL OR doc.expire_date >= CURRENT_DATE)
ORDER BY doc.update_time DESC, chunk.sort_no ASC LIMIT #{request.topN}
